package com.veetu.vadagai.auth;import com.veetu.vadagai.auth.AuthDtos.*;import com.veetu.vadagai.common.ApiResponse;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/auth") @RequiredArgsConstructor public class AuthController{private final AuthService svc;@PostMapping("/register") ApiResponse<TokenResponse> register(@Valid @RequestBody RegisterRequest r){return ApiResponse.ok("Registered",svc.register(r));}@PostMapping("/login") ApiResponse<TokenResponse> login(@Valid @RequestBody LoginRequest r){return ApiResponse.ok("Authenticated",svc.login(r));}@PostMapping("/refresh") ApiResponse<TokenResponse> refresh(@Valid @RequestBody RefreshRequest r){return ApiResponse.ok("Token refreshed",svc.refresh(r));}@PostMapping("/forgot-password") ApiResponse<Void> forgot(@Valid @RequestBody ForgotPasswordRequest r){svc.forgot(r);return ApiResponse.ok("If the email exists, an OTP was sent",null);}@PostMapping("/reset-password") ApiResponse<Void> reset(@Valid @RequestBody ResetPasswordRequest r){svc.reset(r);return ApiResponse.ok("Password updated",null);}}
